import{_ as a,o as n,c as o,ag as i}from"./chunks/framework.BDReElpY.js";const m=JSON.parse('{"title":"VUMM: Vex Universal Memory Manager","description":"","frontmatter":{},"headers":[],"relativePath":"guide/memory/vumm.md","filePath":"guide/memory/vumm.md"}'),s={name:"guide/memory/vumm.md"};function t(r,e,l,c,d,h){return n(),o("div",null,[...e[0]||(e[0]=[i(`<h1 id="vumm-vex-universal-memory-manager" tabindex="-1">VUMM: Vex Universal Memory Manager <a class="header-anchor" href="#vumm-vex-universal-memory-manager" aria-label="Permalink to &quot;VUMM: Vex Universal Memory Manager&quot;">​</a></h1><p>VUMM (Vex Universal Memory Manager) is the core memory management strategy in Vex. Its primary goal is to provide <strong>automatic, efficient ownership transitions</strong> without a garbage collector, ensuring that data is managed correctly and safely across unique, shared, and concurrent contexts.</p><h2 id="the-design-philosophy-zero-ceremony" tabindex="-1">The Design Philosophy: Zero Ceremony <a class="header-anchor" href="#the-design-philosophy-zero-ceremony" aria-label="Permalink to &quot;The Design Philosophy: Zero Ceremony&quot;">​</a></h2><p>In ordinary Vex code, you don&#39;t choose between a separate <code>Rc</code> or <code>Arc</code> type hierarchy. The heap-owning abstraction you work with is always <code>Box</code>.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">let</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> a </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Box</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">new</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">42</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">let</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> b </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Box</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">99</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>Behind this simple interface, VUMM dynamically chooses the underlying memory management strategy. It combines value-based move semantics with automatic reference counting, scaling thread-safety guarantees only when concurrency is actually introduced.</p><hr><h2 id="internal-ownership-states" tabindex="-1">Internal Ownership States <a class="header-anchor" href="#internal-ownership-states" aria-label="Permalink to &quot;Internal Ownership States&quot;">​</a></h2><p>VUMM manages three primary ownership modes for heap-allocated data:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                  Clone (same thread)</span></span>
<span class="line"><span>  ┌───────────┐  ────────────────────→  ┌─────────────┐</span></span>
<span class="line"><span>  │  Unique   │                         │  SharedRc   │</span></span>
<span class="line"><span>  │ (Box&lt;T&gt;)  │  ←────────────────────  │ (Ref Count) │</span></span>
<span class="line"><span>  └───────────┘    Only 1 ref remaining  └─────────────┘</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        │ Share across &#39;go&#39; block</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>  ┌─────────────┐</span></span>
<span class="line"><span>  │  AtomicArc  │ (Atomic Ref Count)</span></span>
<span class="line"><span>  └─────────────┘</span></span></code></pre></div><h3 id="_1-unique-ownership-unique" tabindex="-1">1. Unique Ownership (<code>Unique</code>) <a class="header-anchor" href="#_1-unique-ownership-unique" aria-label="Permalink to &quot;1. Unique Ownership (\`Unique\`)&quot;">​</a></h3><ul><li><strong>Role</strong>: The data has exactly one owner (equivalent to Rust&#39;s <code>Box&lt;T&gt;</code>).</li><li><strong>Performance</strong>: Supports in-place mutation and efficient, zero-overhead moves.</li><li><strong>Deallocation</strong>: Freed immediately when the owning variable goes out of scope.</li></ul><h3 id="_2-shared-reference-counting-sharedrc" tabindex="-1">2. Shared Reference Counting (<code>SharedRc</code>) <a class="header-anchor" href="#_2-shared-reference-counting-sharedrc" aria-label="Permalink to &quot;2. Shared Reference Counting (\`SharedRc\`)&quot;">​</a></h3><ul><li><strong>Role</strong>: The data is reference-counted and shared among multiple owners on the same thread.</li><li><strong>Transition</strong>: Triggered automatically when a <code>Box</code> is cloned within a non-concurrent context.</li><li><strong>Performance</strong>: Cloning simply performs a fast reference count increment (<code>vex_rc_retain</code>) instead of a deep copy, providing value semantics with zero overhead.</li></ul><h3 id="_3-atomic-shared-reference-counting-atomicarc" tabindex="-1">3. Atomic Shared Reference Counting (<code>AtomicArc</code>) <a class="header-anchor" href="#_3-atomic-shared-reference-counting-atomicarc" aria-label="Permalink to &quot;3. Atomic Shared Reference Counting (\`AtomicArc\`)&quot;">​</a></h3><ul><li><strong>Role</strong>: The data is shared across thread boundaries with atomic reference counting for thread safety.</li><li><strong>Transition</strong>: Triggered automatically when a shared <code>Box</code> is captured inside a <code>go</code> block or passed to a concurrent task.</li><li><strong>Performance</strong>: Uses atomic fetch-and-add operations (<code>vex_arc_retain</code>) to prevent data races.</li></ul><hr><h2 id="relationship-with-contracts" tabindex="-1">Relationship with Contracts <a class="header-anchor" href="#relationship-with-contracts" aria-label="Permalink to &quot;Relationship with Contracts&quot;">​</a></h2><p>VUMM leverages Vex&#39;s contract-based system to automate lifetime management:</p><ul><li><strong><code>Copy</code></strong>: Primitive types (numbers, bools, raw pointers) copy on assignment. Owning VUMM types do not implement <code>Copy</code> and default to move semantics.</li><li><strong><code>Clone</code></strong>: Cloning a VUMM type triggers a cheap reference count increment (<code>vex_rc_retain</code> or <code>vex_arc_retain</code>) under the hood instead of duplicating heap allocations, unless a deep copy is explicitly requested.</li><li><strong><code>Drop</code></strong>: VUMM automatically decrements reference counts when an owner leaves scope, freeing the underlying allocation once the reference count reaches zero.</li></ul><hr><h2 id="monomorphized-drop-calls" tabindex="-1">Monomorphized Drop Calls <a class="header-anchor" href="#monomorphized-drop-calls" aria-label="Permalink to &quot;Monomorphized Drop Calls&quot;">​</a></h2><p>To eliminate brittle, complex inline drop glue for generic containers (e.g., <code>Vec&lt;T&gt;</code>), the Vex compiler uses a <strong>Monomorphized Drop Call</strong> strategy:</p><ol><li><strong>Explicit Monomorphization</strong>: The compiler analyzes concrete generic types at compile time (e.g., <code>Vec&lt;String&gt;</code>).</li><li><strong>Direct Call Emission</strong>: When a container is dropped, Vex emits a direct call to the monomorphized user <code>drop()</code> function (e.g., <code>call void @&quot;drop@Vec_String&quot;</code>).</li><li><strong>Safety</strong>: This ensures both the container allocation and its elements are cleaned up correctly according to the specific type <code>T</code>, preventing &quot;orphan drops&quot; and Use-After-Free (UAF) errors.</li></ol><hr><h2 id="memory-allocator-integration" tabindex="-1">Memory Allocator Integration <a class="header-anchor" href="#memory-allocator-integration" aria-label="Permalink to &quot;Memory Allocator Integration&quot;">​</a></h2><p>VUMM is backed by a custom runtime memory allocator designed for low latency:</p><ul><li><strong>Slab Allocator</strong>: Reuses uniform memory chunks in a thread-local pool to avoid expensive syscalls.</li><li><strong>Epoch Quiescence</strong>: FFI and dynamic allocations are retired via epoch-based reclamation, ensuring memory is reclaimed only when no active execution thread holds a reference.</li><li><strong>Zero-Copy Unified Memory</strong>: On Apple Silicon and supported APUs, VUMM maps buffers directly between CPU and GPU without copy overhead.</li></ul><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">TL;DR</p><ol><li><strong>Write <code>Box(value)</code></strong> - Vex has no explicit <code>Rc</code> or <code>Arc</code> types.</li><li><strong>VUMM chooses</strong> between Unique, SharedRc, and AtomicArc automatically at compile time.</li><li><strong>Fast Clones</strong>: Cloning VUMM values increments reference counts instead of deep-copying.</li><li><strong>Monomorphized Drop</strong>: Frees generic containers and elements safely using concrete drop functions.</li><li><strong>Compile Flag</strong>: Use <code>--explain-boxing</code> to inspect VUMM&#39;s decisions during compilation.</li></ol></div><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="./borrowing">Borrowing</a> - Reference rules and NLL</li><li><a href="./lifetimes">Lifetimes</a> - Lifetime elision and regions</li><li><a href="./../types/contracts">Contracts</a> - Contract system</li></ul>`,33)])])}const g=a(s,[["render",t]]);export{m as __pageData,g as default};
